{
var seed = GetInt(parameters, "seed", context.Seed);
    var iconType = GetChoice(parameters, "iconType", "heart");
    var size = GetFloat(parameters, "size", 0.6f);
    var primary = GetColor(parameters, "primaryColor", Color.FromRgb(220, 60, 60));
    var secondary = GetColor(parameters, "secondaryColor", Color.FromRgb(180, 40, 40));

    var tileSize = context.TileSize;
    var buffer = new PixelBuffer(tileSize, tileSize);

    var pR = primary.R / 255f; var pG = primary.G / 255f; var pB = primary.B / 255f;
    var sR = secondary.R / 255f; var sG = secondary.G / 255f; var sB = secondary.B / 255f;

    var halfSize = tileSize * 0.5f;
    var radius = halfSize * size;

    buffer.ParallelForEachPixel((x, y) =>
    {
        var px = (x + 0.5f - halfSize) / radius;
        var py = (y + 0.5f - halfSize) / radius;

        float alpha = 0f;
        float fr = pR, fg = pG, fb = pB;

        switch (iconType)
        {
            case "heart":
                RenderHeart(px, py, out alpha);
                break;
            case "star":
                RenderStar(px, py, out alpha);
                // Gold color
                fr = 0.95f; fg = 0.8f; fb = 0.15f;
                break;
            case "gear":
                RenderGear(px, py, out alpha);
                fr = 0.6f; fg = 0.6f; fb = 0.65f;
                break;
            case "mapMarker":
                RenderMapMarker(px, py, out alpha);
                break;
            case "trophy":
                RenderTrophy(px, py, out alpha);
                fr = 0.9f; fg = 0.75f; fb = 0.2f;
                break;
            case "skull":
                RenderSkull(px, py, seed, out alpha);
                fr = 0.85f; fg = 0.85f; fb = 0.85f;
                break;
        }

        if (alpha <= 0.01f)
        {
            buffer.SetPixel(x, y, 0, 0, 0, 0);
            return;
        }

        // Apply shading (center lighter, edges darker)
        var shade = 0.7f + 0.3f * (1f - MathF.Sqrt(px * px + py * py) * 0.8f);
        var hR = fr * shade; var hG = fg * shade; var hB = fb * shade;

        // Inner highlight offset to upper-left
        var hlDist = MathF.Sqrt((px + 0.3f) * (px + 0.3f) + (py + 0.3f) * (py + 0.3f));
        var hl = MathF.Exp(-hlDist * hlDist * 3f) * 0.3f;

        buffer.SetPixel(x, y,
            Math.Clamp(hR + hl, 0f, 1f),
            Math.Clamp(hG + hl, 0f, 1f),
            Math.Clamp(hB + hl, 0f, 1f), alpha);
    });

    return buffer;

private static void RenderHeart(float px, float py, out float alpha)
{
    // Heart SDF: two circles + inverted triangle
    var leftLobe = MathF.Sqrt((px + 0.3f) * (px + 0.3f) + (py - 0.15f) * (py - 0.15f));
    var rightLobe = MathF.Sqrt((px - 0.3f) * (px - 0.3f) + (py - 0.15f) * (py - 0.15f));
    var bottom = MathF.Sqrt(px * px + (py + 0.4f) * (py + 0.4f));

    var d = MathF.Min(MathF.Min(leftLobe, rightLobe), bottom) - 0.5f;

    // The bottom triangle between lobes
    var tri = MathF.Abs(px) * 0.8f + (py + 0.1f) * 0.6f;
    d = MathF.Max(d, tri - 0.15f);

    alpha = 1f - SmoothStep(0f, 0.12f, d);
}

private static void RenderStar(float px, float py, out float alpha)
{
    // 5-pointed star using angular modulation
    var angle = MathF.Atan2(py, px);
    var dist = MathF.Sqrt(px * px + py * py);
    var spikes = MathF.Cos(angle * 5f) * 0.4f + 0.6f;
    var starDist = dist / (spikes * 0.9f);

    alpha = 1f - SmoothStep(0.7f, 1f, starDist);
}

private static void RenderGear(float px, float py, out float alpha)
{
    var dist = MathF.Sqrt(px * px + py * py);
    var angle = MathF.Atan2(py, px);

    // Tooth modulation
    var teeth = MathF.Cos(angle * 8f) * 0.15f;
    var innerR = 0.4f + teeth;
    var outerR = 0.55f + teeth;

    if (dist < innerR)
    {
        // Inner solid circle
        alpha = 1f;
    }
    else if (dist < outerR)
    {
        // Tooth zone: check if we're on a tooth or in a gap
        var toothMask = MathF.Cos(angle * 8f);
        if (toothMask > 0f)
            alpha = 1f; // Tooth
        else
            alpha = dist < 0.5f ? 1f : 0f; // Inner ring in gap
    }
    else
    {
        alpha = 0f;
    }

    // Center hole
    if (dist < 0.12f) alpha = 0f;
}

private static void RenderMapMarker(float px, float py, out float alpha)
{
    // Map marker: circle on top + triangle pointing down
    var circleDist = MathF.Sqrt(px * px + (py + 0.15f) * (py + 0.15f));
    var inCircle = circleDist < 0.35f;

    var triX = MathF.Abs(px);
    var triY = py - 0.2f;
    var inTriangle = triX < 0.15f * (1f - triY * 1.5f) && triY > 0f && triY < 0.6f;

    if (inCircle || inTriangle)
    {
        // Feather edges
        var edge = inCircle ? circleDist / 0.35f : 1f;
        alpha = Math.Clamp(1f - (edge - 0.85f) / 0.15f, 0f, 1f);
    }
    else
    {
        alpha = 0f;
    }
}

private static void RenderTrophy(float px, float py, out float alpha)
{
    // Trophy: cup shape with handles
    var cupBody = MathF.Max(MathF.Abs(px) - 0.3f, MathF.Abs(py + 0.1f) - 0.3f);
    cupBody = MathF.Max(cupBody, -0.1f);

    // Handles (left and right arcs)
    var leftHandle = MathF.Sqrt((px + 0.35f) * (px + 0.35f) + (py + 0.1f) * (py + 0.1f));
    var rightHandle = MathF.Sqrt((px - 0.35f) * (px - 0.35f) + (py + 0.1f) * (py + 0.1f));
    var handleWidth = 0.06f;

    // Base
    var baseRect = MathF.Max(MathF.Abs(px) - 0.2f, py - 0.4f);

    var d = MathF.Min(MathF.Min(cupBody, MathF.Abs(leftHandle - 0.35f) - handleWidth), MathF.Abs(rightHandle - 0.35f) - handleWidth);
    d = MathF.Min(d, baseRect + 0.05f);

    alpha = 1f - SmoothStep(-0.05f, 0.08f, d);
}

private static void RenderSkull(float px, float py, int seed, out float alpha)
{
    // Skull: rounded head shape
    var headDist = MathF.Sqrt(px * px * 1.2f + py * py);
    var headR = 0.55f;

    if (headDist > headR)
    {
        alpha = 0f;
        return;
    }

    // Jaw cutout
    var jawCut = MathF.Max(MathF.Abs(px) - 0.2f, -py - 0.1f);

    // Eye sockets
    var leftEye = MathF.Sqrt((px + 0.2f) * (px + 0.2f) + (py - 0.1f) * (py - 0.1f));
    var rightEye = MathF.Sqrt((px - 0.2f) * (px - 0.2f) + (py - 0.1f) * (py - 0.1f));

    // Nose
    var nose = MathF.Sqrt(px * px * 0.5f + (py + 0.05f) * (py + 0.05f) * 2f);

    // Mouth: horizontal slit
    var mouth = MathF.Max(MathF.Abs(px) - 0.25f, MathF.Abs(py + 0.25f) - 0.03f);

    if (jawCut > 0f)
    {
        alpha = (jawCut < 0.05f) ? 1f - jawCut / 0.05f : 0f;
        return;
    }

    if (leftEye < 0.1f || rightEye < 0.1f)
    {
        alpha = 0f; // Eye sockets are empty
        return;
    }

    if (nose < 0.06f)
    {
        alpha = 0f;
        return;
    }

    if (mouth < 0f)
    {
        alpha = 0f;
        return;
    }

    alpha = 1f;
    }
}
